#include<bits/stdc++.h>
using namespace std;
int main(void){
	int n,m,a[1005][1005],x,flag[1005][5005],l,ans=0,f;
	cin>>n>>m;l=m;
	for(int i=0;i<n;i++)
		for(int j=0;j<m;j++)cin>>a[i][j];
	for(int i=0;i<n;i++){
		cin>>m;
		for(int j=0;j<m;j++){
			cin>>x;
			flag[i][x]=1;
		}
	}
	for(int i=0;i<n;i++){
		f=0;
		for(int j=0;j<l;j++){
			if(flag[i][a[i][j]]){
				f++;
			}
		}
		if(f==l)ans+=2;
	}
	cout<<ans;
    return false;
}
